UPDATE services SET customerExternalId = 'C7554' WHERE externalId = 'IPTEL-AB038552' AND (customerExternalId IS NULL OR customerExternalId = '');

-- Action Smart End 2 End (IPTEL-AB056135) → Action Smart Group (cust-action-smart-group)
UPDATE services SET customerExternalId = 'cust-action-smart-group' WHERE externalId = 'IPTEL-AB056135' AND (customerExternalId IS NULL OR customerExternalId = '');

-- Kate Mobile, Ian Mobile, Cindy Mobile, Caitlin Mobile, Ian-T14 → Smile IT internal (C2441)
UPDATE services SET customerExternalId = 'C2441' WHERE externalId IN ('S0313','S0310','S0312','S0315','S0311') AND (customerExternalId IS NULL OR customerExternalId = '');

-- Shenanigans (S0314) → need to find customer; check phone 0457857453 against matched services
UPDATE services AS u
JOIN (
  SELECT customerExternalId FROM services 
  WHERE REPLACE(phoneNumber,' ','') = '0457857453' AND customerExternalId IS NOT NULL AND customerExternalId != ''
  LIMIT 1
) AS m SET u.customerExternalId = m.customerExternalId
WHERE u.externalId = 'S0314' AND (u.customerExternalId IS NULL OR u.customerExternalId = '');

SELECT ROW_COUNT() AS shenanigans_phone_match;

-- Count total updated so far
SELECT COUNT(*) AS still_unmatched FROM services WHERE customerExternalId IS NULL OR customerExternalId = '';

